const results = $input.first().json.results || [];
const posts = [];
const skipped = [];

results.forEach(page => {
  const props = page.properties;
  const titel = props?.['Titel']?.title?.[0]?.plain_text || 'Ohne Titel';
  const linkedin_post = props?.['LinkedIn-Post']?.rich_text?.[0]?.plain_text || '';
  const hook = props?.['Hook']?.rich_text?.[0]?.plain_text || '';
  const saeule = props?.['Säule']?.select?.name || '-';
  const post_typ = props?.['Type']?.rich_text?.[0]?.plain_text || '';

  if (!linkedin_post.trim()) {
    skipped.push(titel);
    return;
  }

  posts.push({
    json: { page_id: page.id, titel, linkedin_post, hook, saeule, post_typ }
  });
});

if (skipped.length > 0) {
  console.log(`Übersprungen (kein LinkedIn-Post): ${skipped.join(', ')}`);
}
console.log(`${posts.length} Posts zur Bild-Prompt-Generierung vorbereitet`);
return posts;

const claudeResponse = $input.first().json;
const prev = $('Posts einzeln verarbeiten').item.json;

const optimierterPrompt = claudeResponse?.content?.[0]?.text?.trim() || '';

if (!optimierterPrompt) {
  console.log(`Kein Prompt erhalten für: ${prev.titel}`);
}

console.log(`Prompt abgeleitet für: ${prev.titel}`);

return [{
  json: {
    page_id: prev.page_id,
    titel: prev.titel,
    image_prompt: optimierterPrompt
  }
}];

const items = $input.all();
const anzahl = items.filter(i => i.json?.image_prompt).length;
console.log(`Image-Prompt-Generierung abgeschlossen – ${anzahl} Prompt(s) erstellt`);
return [{ json: { status: 'Abgeschlossen', verarbeitet: anzahl } }];

const count = $('Abschluss-Log').first().json.verarbeitet;
const heute = new Date().toLocaleDateString('de-DE');

return [{
  json: {
    to: 'wolfgang.baierl@blboardsolutions.de',
    subject: `[LinkedIn] ${count} Bildprompt(s) generiert – bereit für DALL-E 3`,
    body: `<div style="font-family:Arial,sans-serif;max-width:600px"><h2 style="color:#2c5282">Image-Prompts generiert</h2><p>Für <strong>${count}</strong> Post(s) wurde ein DALL-E 3 Bildprompt aus dem LinkedIn-Text abgeleitet und im Feld <em>ImagePrompt</em> gespeichert.</p><hr style="margin:20px 0"><p><strong>So nutzt du die Prompts:</strong></p><ol><li>Content Pipeline in Notion öffnen</li><li>Beim gewünschten Post das Feld <em>ImagePrompt</em> kopieren</li><li>In <a href=\"https://chat.openai.com\">ChatGPT → DALL-E 3</a> oder <a href=\"https://www.bing.com/images/create\">Bing Image Creator</a> einfügen</li><li>Generiertes Bild herunterladen und zum Post hinzufügen</li><li>Checkbox <em>ImagePrompt generieren</em> in Notion deaktivieren</li></ol><p><a href=\"https://www.notion.so/35147c762802803f8311ce87bcce27a5\" style=\"background:#2c5282;color:#fff;padding:10px 20px;text-decoration:none;border-radius:4px;display:inline-block\">→ Content Pipeline öffnen</a></p><p style=\"color:#999;font-size:0.8em;margin-top:30px\">Automatisch generiert am ${heute} · n8n LinkedIn-Workflow</p></div>`
  }
}];
